    }
  },
  "inputSchema": {
    "type": "object",
    "additionalProperties": false,
    "required": [
      "recommendation"
    ],
    "properties": {
      "recommendation": {
        "type": "object",
        "description": "Candidate recommendation JSON with text, reasoning, confidence, keyFindings, and suggestions fields."
      }
    }
  }
}

